# Terraform configuration for a PagerDuty alert rule that links to the correct runbook
# This reduces the time from alert to runbook from minutes to seconds.

resource "pagerduty_event_orchestration_service" "agent_service" {
  service = pagerduty_service.agent_service.id

  set {
    id = "start"

    rule {
      condition {
        expression = "event.summary matches 'agent_error_rate_high'"
      }
      actions {
        annotate = "Runbook: https://wiki.example.com/runbooks/agent-error-rate"
        severity = "critical"
        priority = "P2"
      }
    }

    rule {
      condition {
        expression = "event.summary matches 'anthropic_rate_limit'"
      }
      actions {
        annotate = "Runbook: https://wiki.example.com/runbooks/rate-limit-429"
        severity = "warning"
        priority = "P3"
      }
    }

    rule {
      condition {
        expression = "event.summary matches 'agent_loop_detected'"
      }
      actions {
        annotate = "Runbook: https://wiki.example.com/runbooks/agent-loop\nIMPORTANT: Apply kill switch first — see Step 1."
        severity = "critical"
        priority = "P1"
      }
    }
  }
}
